from flask import Flask, request, jsonify
import jwt
import requests
import os
from functools import wraps

app = Flask(__name__)

# JWT Configuration
JWT_SECRET = os.environ.get('JWT_SECRET', 'your-secret-key-change-in-production')
JWT_ALGORITHM = 'HS256'
JWT_ISSUER = os.environ.get('JWT_ISSUER', 'your-issuer')
JWT_AUDIENCE = os.environ.get('JWT_AUDIENCE', 'your-audience')

# Backend service URL
BACKEND_SERVICE_URL = os.environ.get('BACKEND_SERVICE_URL', 'http://localhost:5001')


def validate_jwt_token(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        
        if not auth_header:
            return jsonify({'error': 'Missing Authorization header'}), 401
        
        parts = auth_header.split()
        
        if len(parts) != 2 or parts[0].lower() != 'bearer':
            return jsonify({'error': 'Invalid Authorization header format. Expected: Bearer <token>'}), 401
        
        token = parts[1]
        
        try:
            # Secure JWT validation with signature verification
            decoded_token = jwt.decode(
                token,
                JWT_SECRET,
                algorithms=[JWT_ALGORITHM],
                options={
                    'verify_signature': True,
                    'verify_exp': True,
                    'verify_nbf': True,
                    'verify_iat': True,
                    'verify_aud': True,
                    'verify_iss': True,
                    'require_exp': True,
                    'require_iat': True
                },
                audience=JWT_AUDIENCE,
                issuer=JWT_ISSUER,
                leeway=10  # Allow 10 seconds of clock skew
            )
            
            # Validate required claims
            required_claims = ['sub', 'exp', 'iat']
            for claim in required_claims:
                if claim not in decoded_token:
                    return jsonify({'error': f'Missing required claim: {claim}'}), 401
            
            # Store user claims in request context
            request.user_claims = decoded_token
            
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError as e:
            return jsonify({'error': f'Invalid token: {str(e)}'}), 401
        except jwt.InvalidSignatureError:
            return jsonify({'error': 'Invalid token signature'}), 401
        except jwt.InvalidAudienceError:
            return jsonify({'error': 'Invalid token audience'}), 401
        except jwt.InvalidIssuerError:
            return jsonify({'error': 'Invalid token issuer'}), 401
        except jwt.ImmatureSignatureError:
            return jsonify({'error': 'Token not yet valid'}), 401
        except Exception as e:
            return jsonify({'error': 'Token validation failed'}), 401
        
        return f(*args, **kwargs)
    
    return decorated_function


@app.route('/api/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
@validate_jwt_token
def gateway(path):
    """
    API Gateway endpoint that forwards requests to backend services
    after validating JWT tokens
    """
    user_claims = request.user_claims
    
    # Prepare headers for backend request
    backend_headers = {
        'X-User-ID': str(user_claims.get('sub', '')),
        'X-User-Email': str(user_claims.get('email', '')),
        'X-User-Roles': ','.join(user_claims.get('roles', [])),
        'Content-Type': request.headers.get('Content-Type', 'application/json')
    }
    
    # Add custom claims as headers
    for key, value in user_claims.items():
        if key not in ['sub', 'email', 'roles', 'exp', 'iat', 'nbf', 'iss', 'aud']:
            header_key = f'X-User-{key.replace("_", "-").title()}'
            if isinstance(value, (str, int, float, bool)):
                backend_headers[header_key] = str(value)
    
    # Construct backend URL
    backend_url = f"{BACKEND_SERVICE_URL}/{path}"
    
    try:
        # Forward request to backend service
        if request.method == 'GET':
            response = requests.get(
                backend_url,
                headers=backend_headers,
                params=request.args,
                timeout=30
            )
        elif request.method == 'POST':
            response = requests.post(
                backend_url,
                headers=backend_headers,
                json=request.get_json(silent=True),
                params=request.args,
                timeout=30
            )
        elif request.method == 'PUT':
            response = requests.put(
                backend_url,
                headers=backend_headers,
                json=request.get_json(silent=True),
                params=request.args,
                timeout=30
            )
        elif request.method == 'DELETE':
            response = requests.delete(
                backend_url,
                headers=backend_headers,
                params=request.args,
                timeout=30
            )
        elif request.method == 'PATCH':
            response = requests.patch(
                backend_url,
                headers=backend_headers,
                json=request.get_json(silent=True),
                params=request.args,
                timeout=30
            )
        else:
            return jsonify({'error': 'Method not allowed'}), 405
        
        # Return backend response
        return (response.content, response.status_code, response.headers.items())
    
    except requests.exceptions.Timeout:
        return jsonify({'error': 'Backend service timeout'}), 504
    except requests.exceptions.ConnectionError:
        return jsonify({'error': 'Backend service unavailable'}), 503
    except Exception as e:
        app.logger.error(f"Error forwarding request: {str(e)}")
        return jsonify({'error': 'Internal gateway error'}), 500


@app.route('/health', methods=['GET'])
def health():
    """Health check endpoint"""
    return jsonify({'status': 'healthy'}), 200


@app.errorhandler(404)
def not_found(e):
    return jsonify({'error': 'Endpoint not found'}), 404


